UPDATE WH_PRESS SET PRS_NAME = IFNULL(#{PRS_NAME}, PRS_NAME),
PRS_PWD = CONCAT('*',UPPER(SHA1(UNHEX(SHA1(#{PRS_PWD}))))),
PRS_EMAIL = IFNULL(#{PRS_EMAIL}, PRS_EMAIL), PRS_HOMEPAGE = IFNULL(#{PRS_HOMEPAGE}, PRS_HOMEPAGE), PRS_USE_YN = IFNULL(#{PRS_USE_YN}, PRS_USE_YN), PRS_TYPE = IFNULL(#{PRS_TYPE}, PRS_TYPE), PRS_AUTH_YN = IFNULL(#{PRS_AUTH_YN}, PRS_AUTH_YN), ORIG_FILE_NM = IFNULL(#{ORIG_FILE_NM}, ORIG_FILE_NM), STORED_FILE_NM = IFNULL(#{STORED_FILE_NM}, STORED_FILE_NM) WHERE PRS_ID = #{PRS_ID}

