SELECT EVT.EVT_ID, (SELECT PRS_NAME FROM WH_PRESS WHERE APP_ID = EVT.APP_ID) PRS_NAME, EVT.APP_ID, EVT.EVT_TEXT, EVT.EVT_BTN_TEXT, EVT.EVT_STAR, EVT.EVT_URL, EVT.EVT_CHG_YN, IF(EVT.EVT_USE_YN = 1, 'Y', 'N') AS EVT_USE_YN, (SELECT COUNT(*) FROM WH_EVENT_HST HST WHERE HST.EVT_ID = EVT.EVT_ID) AS CNT FROM WH_EVENT EVT WHERE 1=1
AND APP_ID = #{APP_ID}
ORDER BY EVT.EVT_ID DESC

SELECT APP_ID
 FROM WH_PRESS 
 WHERE PRS_ID = #{PRS_ID}

WITH RECURSIVE date_range AS ( SELECT CURDATE() - INTERVAL 29 DAY AS usage_date UNION ALL SELECT usage_date + INTERVAL 1 DAY FROM date_range WHERE usage_date + INTERVAL 1 DAY <= CURDATE() ), price_agg AS ( SELECT DATE(PRI_CREATE_DATE) AS usage_date, SUM(CON_PRICE) AS empty_star, SUM(CON_PRICE_CHG) AS filled_star FROM WH_PRICE
WHERE PRS_ID = #{PRS_ID}
GROUP BY DATE(PRI_CREATE_DATE) ), heart_agg AS ( SELECT DATE(HRT_CREATE_DATE) AS usage_date, SUM(CON_HEART) AS empty_heart, SUM(CON_HEART_CHG) AS filled_heart FROM WH_HEART
WHERE PRS_ID = #{PRS_ID}
GROUP BY DATE(HRT_CREATE_DATE) ) SELECT DATE_FORMAT(d.usage_date, '%m/%d') AS usage_date, COALESCE(p.empty_star, 0) AS empty_star, COALESCE(p.filled_star, 0) AS filled_star, COALESCE(h.empty_heart, 0) AS empty_heart, COALESCE(h.filled_heart, 0) AS filled_heart FROM date_range d LEFT JOIN price_agg p ON p.usage_date = d.usage_date LEFT JOIN heart_agg h ON h.usage_date = d.usage_date ORDER BY d.usage_date;

WITH RECURSIVE month_range AS ( SELECT DATE_FORMAT(CURDATE() - INTERVAL 11 MONTH, '%Y-%m-01') AS usage_month UNION ALL SELECT DATE_ADD(usage_month, INTERVAL 1 MONTH) FROM month_range WHERE usage_month < DATE_FORMAT(CURDATE(), '%Y-%m-01') ), price_agg AS ( SELECT DATE_FORMAT(w.PRI_CREATE_DATE, '%Y-%m') AS ym, SUM(w.CON_PRICE) AS empty_star, SUM(w.CON_PRICE_CHG) AS filled_star FROM WH_PRICE w
WHERE w.PRS_ID = #{PRS_ID}
GROUP BY DATE_FORMAT(w.PRI_CREATE_DATE, '%Y-%m') ), heart_agg AS ( SELECT DATE_FORMAT(h.HRT_CREATE_DATE, '%Y-%m') AS ym, SUM(h.CON_HEART) AS empty_heart, SUM(h.CON_HEART_CHG) AS filled_heart FROM WH_HEART h
WHERE h.PRS_ID = #{PRS_ID}
GROUP BY DATE_FORMAT(h.HRT_CREATE_DATE, '%Y-%m') ) SELECT DATE_FORMAT(m.usage_month, '%y/%m') AS usage_date, COALESCE(p.empty_star, 0) AS empty_star, COALESCE(p.filled_star, 0) AS filled_star, COALESCE(h.empty_heart, 0) AS empty_heart, COALESCE(h.filled_heart, 0) AS filled_heart FROM month_range m LEFT JOIN price_agg p ON p.ym = DATE_FORMAT(m.usage_month, '%Y-%m') LEFT JOIN heart_agg h ON h.ym = DATE_FORMAT(m.usage_month, '%Y-%m') ORDER BY m.usage_month;
